INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Pengantar: Ulama Nusantara, Penerus Para Wali', 'ulama-nusantara-00-pengantar', 'id', 'ulama-nusantara', 1, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Setelah masa Wali Songo, dakwah Islam di Nusantara tidak berhenti — ia justru memasuki babak baru yang kaya: babak keilmuan. Muncullah generasi ulama besar yang tidak hanya menyebarkan Islam, tetapi juga menuliskannya, mengajarkannya secara sistematis, dan membangun lembaga-lembaga yang bertahan hingga hari ini.

Mereka datang dari berbagai penjuru: Aceh yang menjadi "Serambi Makkah", Palembang, Banten, Minangkabau, Makassar, hingga tanah Jawa. Sebagian menulis kitab dalam bahasa Melayu dan Arab yang dibaca lintas generasi; sebagian mengajar di Makkah dan menjadi guru bagi ulama sedunia; sebagian mendirikan organisasi dan pesantren yang membentuk wajah Islam Indonesia modern.

Yang menyatukan mereka adalah tradisi keilmuan yang mendalam, kecintaan pada umat, dan kemampuan memadukan kesalehan dengan keberpihakan pada kemajuan. Banyak dari mereka kemudian diakui negara sebagai Pahlawan Nasional.

Dalam seri ini kita akan menelusuri kisah sebagian dari mereka — dari Hamzah Fansuri di Aceh hingga Buya Hamka di zaman modern — sebagai penghormatan dan sumber pelajaran.

Sumber & Catatan: kisah para ulama ini sebagian besar bersumber dari sejarah yang terdokumentasi kuat — karya-karya tulis mereka yang masih ada, lembaga yang mereka dirikan, catatan tanggal, serta pengakuan resmi negara (gelar Pahlawan Nasional). Di mana ada riwayat yang bersifat tradisi atau cerita karomah, hal itu akan disebutkan secara khusus. Rincian tahun kadang sedikit berbeda antar sumber sejarah.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Introduction: The Scholars of the Archipelago, Heirs of the Saints', 'ulama-nusantara-00-pengantar', 'en', 'ulama-nusantara', 1, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'After the age of the Wali Songo, the mission of Islam in the archipelago did not stop — it entered a rich new chapter: the chapter of scholarship. A generation of great scholars arose who did not merely spread Islam but wrote it down, taught it systematically, and built institutions that endure to this day.

They came from every corner: Aceh, which became "the Verandah of Makkah"; Palembang; Banten; Minangkabau; Makassar; and the land of Java. Some wrote books in Malay and Arabic read across generations; some taught in Makkah and became teachers to scholars worldwide; some founded organisations and pesantren that shaped the face of modern Indonesian Islam.

What united them was a deep scholarly tradition, a love for the community, and the ability to blend piety with a commitment to progress. Many were later recognised by the state as National Heroes.

In this series we trace the stories of some of them — from Hamzah Fansuri in Aceh to Buya Hamka in the modern age — as an honour to them and a source of lessons.

Sources & Notes: the stories of these scholars rest largely on strongly documented history — their surviving written works, the institutions they founded, recorded dates, and official state recognition (the National Hero title). Where an account is traditional or a karomah story, that is noted specifically. Dates sometimes differ slightly between historical sources.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Syekh Hamzah Fansuri — Penyair Sufi dari Aceh', 'ulama-nusantara-01-hamzah-fansuri', 'id', 'ulama-nusantara', 2, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Hamzah Fansuri, yang hidup sekitar akhir abad ke-16, dikenal sebagai salah satu ulama sufi dan penyair terbesar dalam sejarah sastra Melayu. Ia berasal dari wilayah Fansur (Barus) di pesisir Sumatra, kawasan yang sejak lama menjadi pintu masuk Islam dan perdagangan.

Sumbangan terbesarnya adalah mengembangkan syair sebagai media dakwah dan pengajaran tasawuf. Ia dianggap sebagai peletak dasar bentuk "syair" dalam kesusastraan Melayu — bait empat baris dengan rima yang kemudian menjadi warisan sastra Nusantara. Melalui syair-syairnya, ia mengajarkan cinta kepada Allah dan penyucian jiwa dengan bahasa yang indah dan mudah dihayati.

Ajaran tasawufnya yang mendalam, yang menekankan kedekatan dengan Allah, sempat menimbulkan perdebatan di kalangan ulama sesudahnya. Namun pengaruhnya terhadap perkembangan pemikiran dan sastra Islam Melayu tidak terbantahkan.

Hikmah: ilmu dan keindahan dapat berpadu. Hamzah Fansuri menunjukkan bahwa kerinduan kepada Allah bisa dituangkan dalam bentuk yang menyentuh hati sekaligus mencerdaskan.

Sumber & Catatan: keberadaan dan pemikiran Hamzah Fansuri terdokumentasi melalui karya-karyanya yang masih dikaji hingga kini, seperti Asrar al-''Arifin, Syarab al-''Asyiqin, dan al-Muntahi, serta kumpulan syairnya. Tahun kelahiran dan wafatnya tidak diketahui pasti dan diperkirakan para sejarawan berdasarkan konteks karyanya. Perdebatan seputar ajaran wahdatul wujud yang dikaitkan dengannya juga tercatat dalam sejarah pemikiran Islam Melayu.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Sheikh Hamzah Fansuri — the Sufi Poet of Aceh', 'ulama-nusantara-01-hamzah-fansuri', 'en', 'ulama-nusantara', 2, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Hamzah Fansuri, who lived around the end of the 16th century, is known as one of the greatest sufi scholars and poets in the history of Malay literature. He came from the region of Fansur (Barus) on the coast of Sumatra, an area that had long been a gateway for Islam and trade.

His greatest contribution was developing verse as a medium for preaching and teaching sufism. He is regarded as the founder of the "syair" form in Malay literature — the four-line rhymed stanza that became a heritage of the archipelago. Through his poems he taught love of God and the purification of the soul in beautiful, deeply felt language.

His profound sufi teaching, emphasising nearness to God, later stirred debate among the scholars who followed. Yet his influence on the development of Malay Islamic thought and literature is undeniable.

Reflection: knowledge and beauty can be joined. Hamzah Fansuri shows that longing for God can be poured into a form that touches the heart and enlightens the mind at once.

Sources & Notes: Hamzah Fansuri''s existence and thought are documented through his still-studied works such as Asrar al-''Arifin, Syarab al-''Asyiqin, and al-Muntahi, together with his collected poetry. His birth and death years are not known precisely and are estimated by historians from the context of his work. The debate over the wahdat al-wujud teaching associated with him is also recorded in the history of Malay Islamic thought.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Syekh Nuruddin ar-Raniri — Mufti dan Sejarawan Aceh', 'ulama-nusantara-02-nuruddin-ar-raniri', 'id', 'ulama-nusantara', 3, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Nuruddin ar-Raniri adalah ulama besar yang berkiprah di Kesultanan Aceh Darussalam pada abad ke-17, pada masa kejayaannya di bawah Sultan Iskandar Tsani. Ia berasal dari Ranir (Rander) di Gujarat, India, namun mengabdikan sebagian besar hidupnya untuk keilmuan Islam di Aceh.

Ia menjabat sebagai Syaikhul Islam (mufti) dan menjadi penasihat keagamaan kesultanan. Ar-Raniri sangat produktif menulis; salah satu karyanya yang paling terkenal adalah "Bustanus Salatin" (Taman Para Raja), sebuah karya ensiklopedis yang memuat sejarah, tata negara, dan ajaran agama — menjadi salah satu sumber sejarah penting Nusantara.

Ar-Raniri dikenal sebagai pembela ajaran ahlussunnah dan mengambil sikap tegas dalam perdebatan tasawuf pada zamannya. Perannya menegaskan bahwa Aceh saat itu bukan hanya pusat kekuasaan, tetapi juga pusat keilmuan Islam yang disegani.

Hikmah: seorang ulama tidak hanya menjaga ibadah, tetapi juga menata pemikiran dan mencatat sejarah agar umat memiliki pijakan. Ilmu yang dituliskan menjadi warisan yang hidup jauh melampaui usia penulisnya.

Sumber & Catatan: kiprah ar-Raniri terdokumentasi kuat melalui karya-karyanya yang masih ada, terutama Bustanus Salatin, serta catatan sejarah Kesultanan Aceh. Ia menulis puluhan karya dalam bahasa Melayu dan Arab. Beberapa perdebatannya dengan pengikut ajaran tertentu tercatat dalam sejarah, dan penilaiannya diperdebatkan para pengkaji modern — hal yang wajar dalam kajian sejarah pemikiran.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Sheikh Nuruddin ar-Raniri — Mufti and Historian of Aceh', 'ulama-nusantara-02-nuruddin-ar-raniri', 'en', 'ulama-nusantara', 3, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Nuruddin ar-Raniri was a great scholar active in the Sultanate of Aceh Darussalam in the 17th century, during its golden age under Sultan Iskandar Thani. He came from Ranir (Rander) in Gujarat, India, yet devoted much of his life to Islamic scholarship in Aceh.

He served as Shaykh al-Islam (mufti) and became the religious advisor to the sultanate. Ar-Raniri was highly prolific; among his most famous works is "Bustanus Salatin" (The Garden of Kings), an encyclopedic work covering history, statecraft, and religious teaching — one of the important historical sources of the archipelago.

Ar-Raniri was known as a defender of Ahl al-Sunnah teaching and took a firm stance in the sufi debates of his time. His role affirmed that Aceh was then not only a centre of power but also a respected centre of Islamic scholarship.

Reflection: a scholar not only guards worship but also orders thought and records history so the community has firm ground. Knowledge written down becomes a living legacy long outlasting its author.

Sources & Notes: ar-Raniri''s career is strongly documented through his surviving works, especially Bustanus Salatin, and the historical records of the Sultanate of Aceh. He wrote dozens of works in Malay and Arabic. Some of his debates with the followers of particular teachings are recorded in history, and modern scholars debate the assessment of them — as is normal in the study of the history of ideas.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Syekh Abdurrauf as-Singkili — Perintis Tafsir Melayu', 'ulama-nusantara-03-abdurrauf-as-singkili', 'id', 'ulama-nusantara', 4, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Abdurrauf as-Singkili, yang berasal dari Singkil di Aceh dan hidup pada abad ke-17, adalah salah satu ulama paling berpengaruh dalam sejarah keilmuan Nusantara. Ia menuntut ilmu bertahun-tahun di Timur Tengah, termasuk Makkah dan Madinah, sebelum kembali mengabdi di Aceh sebagai mufti.

Karyanya yang paling monumental adalah "Tarjuman al-Mustafid", yang secara luas dikenal sebagai tafsir lengkap Al-Qur''an pertama dalam bahasa Melayu. Karya ini menjadikan makna Al-Qur''an dapat diakses oleh masyarakat Nusantara dalam bahasa mereka sendiri — sebuah lompatan besar bagi penyebaran pemahaman Islam.

Ia juga menyebarkan Tarekat Syattariyah secara damai dan menekankan keseimbangan antara syariat dan tasawuf. Namanya begitu dihormati hingga diabadikan sebagai "Syiah Kuala" — dan menjadi nama Universitas Syiah Kuala di Banda Aceh hari ini.

Hikmah: membuka pintu ilmu bagi orang banyak adalah amal yang mengalir panjang. Dengan menerjemahkan makna Al-Qur''an, as-Singkili memberi umatnya cahaya yang bisa mereka baca sendiri.

Sumber & Catatan: kiprah as-Singkili terdokumentasi melalui karya-karyanya yang masih ada, terutama Tarjuman al-Mustafid, serta catatan penyebaran Tarekat Syattariyah di Nusantara. Pengabadian namanya sebagai "Syiah Kuala" dan penamaan universitas negeri atas namanya adalah fakta yang dapat diverifikasi hingga kini.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Sheikh Abdurrauf as-Singkili — Pioneer of the Malay Qur''an Commentary', 'ulama-nusantara-03-abdurrauf-as-singkili', 'en', 'ulama-nusantara', 4, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Abdurrauf as-Singkili, from Singkil in Aceh and living in the 17th century, was one of the most influential scholars in the history of archipelago learning. He studied for many years in the Middle East, including Makkah and Madinah, before returning to serve in Aceh as mufti.

His most monumental work is "Tarjuman al-Mustafid," widely known as the first complete commentary on the Qur''an in the Malay language. This work made the meaning of the Qur''an accessible to the people of the archipelago in their own tongue — a great leap for the spread of Islamic understanding.

He also spread the Shattariyya order peacefully and stressed the balance between the sacred law and sufism. His name was so honoured that it was immortalised as "Syiah Kuala" — and is today the name of Syiah Kuala University in Banda Aceh.

Reflection: opening the door of knowledge to the many is a deed that flows on and on. By rendering the meaning of the Qur''an, as-Singkili gave his people a light they could read for themselves.

Sources & Notes: as-Singkili''s career is documented through his surviving works, especially Tarjuman al-Mustafid, and records of the spread of the Shattariyya order in the archipelago. The immortalisation of his name as "Syiah Kuala" and the naming of a state university after him are facts verifiable to this day.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Syekh Yusuf al-Makassari — Ulama, Pejuang, dan Perantau', 'ulama-nusantara-04-syekh-yusuf-al-makassari', 'id', 'ulama-nusantara', 5, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Syekh Yusuf al-Makassari (1626–1699) adalah salah satu ulama Nusantara yang paling luar biasa perjalanan hidupnya. Lahir di Gowa, Sulawesi Selatan, ia menuntut ilmu hingga ke Makkah, Madinah, dan berbagai pusat keilmuan Islam, lalu menjadi ulama besar dengan pengaruh lintas negeri.

Ia kemudian mengabdi di Kesultanan Banten dan turut memimpin perlawanan terhadap penjajahan Belanda. Karena itu ia ditangkap dan diasingkan — mula-mula ke Sri Lanka, lalu ke Cape Town, Afrika Selatan. Di tanah pengasingan itu, alih-alih padam, ia justru menjadi peletak dasar komunitas Muslim di Afrika Selatan; hingga kini ia dihormati sebagai salah satu tokoh pendiri Islam di sana.

Syekh Yusuf adalah lambang bahwa ilmu dan keteguhan tidak mengenal batas wilayah. Ia diakui sebagai Pahlawan Nasional Indonesia, dan namanya dihormati di tiga negara: Indonesia, Afrika Selatan, dan Sri Lanka. Makamnya ada di Cape Town dan juga di Gowa.

Hikmah: seorang mukmin sejati tetap menebar manfaat di mana pun ia berada, bahkan di tempat pembuangan. Ujian dan keterasingan tidak menghentikan cahaya ilmu untuk terus bersinar.

Sumber & Catatan: kisah Syekh Yusuf termasuk yang paling terdokumentasi — pengasingannya oleh Belanda, perannya di Afrika Selatan, gelar Pahlawan Nasional Indonesia (ditetapkan 1995), dan keberadaan makamnya di Cape Town serta Gowa adalah fakta sejarah yang tercatat resmi. Sejumlah karya tasawufnya juga masih dikaji.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Sheikh Yusuf al-Makassari — Scholar, Fighter, and Wanderer', 'ulama-nusantara-04-syekh-yusuf-al-makassari', 'en', 'ulama-nusantara', 5, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Sheikh Yusuf al-Makassari (1626–1699) was one of the most extraordinary of the archipelago''s scholars in the course of his life. Born in Gowa, South Sulawesi, he sought knowledge as far as Makkah, Madinah, and various centres of Islamic learning, then became a great scholar with cross-border influence.

He later served in the Sultanate of Banten and helped lead the resistance against Dutch colonisation. For this he was captured and exiled — first to Sri Lanka, then to Cape Town, South Africa. In that land of exile, rather than being extinguished, he became a founder of the Muslim community in South Africa; to this day he is honoured there as one of the founding figures of Islam.

Sheikh Yusuf is a symbol that knowledge and steadfastness know no borders. He is recognised as an Indonesian National Hero, and his name is honoured in three countries: Indonesia, South Africa, and Sri Lanka. His tombs are in Cape Town and also in Gowa.

Reflection: a true believer keeps spreading benefit wherever he is, even in a place of banishment. Trial and exile did not stop the light of knowledge from shining on.

Sources & Notes: the story of Sheikh Yusuf is among the most documented — his exile by the Dutch, his role in South Africa, his Indonesian National Hero title (conferred 1995), and the existence of his tombs in Cape Town and Gowa are officially recorded historical facts. Several of his sufi works are also still studied.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Syekh Abdus Shamad al-Palimbani — Ulama Sufi dari Palembang', 'ulama-nusantara-05-abdus-shamad-al-palimbani', 'id', 'ulama-nusantara', 6, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Abdus Shamad al-Palimbani, yang hidup pada abad ke-18, adalah ulama besar dari Palembang, Sumatra Selatan. Seperti banyak ulama Nusantara pada masanya, ia menetap lama di Makkah untuk menuntut dan mengajarkan ilmu, menjadi bagian dari jaringan ulama internasional.

Ia terkenal karena karya-karyanya dalam bidang tasawuf, terutama "Sairus Salikin" dan "Hidayatus Salikin", yang merupakan saduran dan penjelasan atas kitab besar Imam al-Ghazali, Ihya'' Ulumuddin, ke dalam bahasa Melayu. Melalui karya-karya ini, pemikiran tasawuf yang mendalam menjadi dapat dijangkau oleh masyarakat Nusantara.

Al-Palimbani juga dikenal menyerukan semangat jihad dan pembelaan terhadap umat, menulis surat-surat yang membangkitkan semangat melawan penjajahan. Ia memadukan kedalaman spiritual dengan kepedulian pada nasib bangsanya.

Hikmah: ilmu yang mendalam menjadi lebih berharga ketika disampaikan dengan bahasa yang mudah dipahami umat. Menyadur dan menjelaskan karya besar adalah bentuk khidmat keilmuan yang mulia.

Sumber & Catatan: kiprah al-Palimbani terdokumentasi melalui karya-karyanya yang masih dibaca hingga kini, terutama Sairus Salikin dan Hidayatus Salikin. Keterkaitannya dengan jaringan ulama Makkah abad ke-18 dicatat dalam kajian sejarah keilmuan Islam Nusantara. Tahun kelahiran dan wafatnya diperkirakan sedikit berbeda antar sumber.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Sheikh Abdus Shamad al-Palimbani — the Sufi Scholar of Palembang', 'ulama-nusantara-05-abdus-shamad-al-palimbani', 'en', 'ulama-nusantara', 6, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Abdus Shamad al-Palimbani, who lived in the 18th century, was a great scholar from Palembang, South Sumatra. Like many archipelago scholars of his day, he stayed long in Makkah to seek and teach knowledge, becoming part of an international network of scholars.

He is renowned for his works in sufism, especially "Sairus Salikin" and "Hidayatus Salikin," which are adaptations and expositions of Imam al-Ghazali''s great work, Ihya'' Ulum al-Din, into Malay. Through these works, profound sufi thought became reachable for the people of the archipelago.

Al-Palimbani was also known for calling to the spirit of jihad and the defence of the community, writing letters that stirred resistance against colonisation. He combined spiritual depth with concern for the fate of his people.

Reflection: deep knowledge becomes more valuable when conveyed in language the community can easily grasp. To adapt and explain a great work is a noble form of scholarly service.

Sources & Notes: al-Palimbani''s career is documented through his still-read works, especially Sairus Salikin and Hidayatus Salikin. His connection to the 18th-century network of Makkan scholars is noted in studies of the history of Islamic learning in the archipelago. His birth and death years are estimated slightly differently between sources.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Syekh Nawawi al-Bantani — Sayyidul Ulama Hijaz', 'ulama-nusantara-06-nawawi-al-bantani', 'id', 'ulama-nusantara', 7, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Syekh Nawawi al-Bantani (1813–1897) berasal dari Banten dan menjadi salah satu ulama Nusantara paling masyhur di dunia Islam. Sejak muda ia menuntut ilmu hingga ke Makkah, lalu menetap dan mengajar di sana selama puluhan tahun, sampai wafat dan dimakamkan di Ma''la, Makkah.

Kedalaman ilmunya membuatnya digelari "Sayyid Ulama al-Hijaz" (pemuka para ulama Hijaz). Ia mengajar di Masjidil Haram dan menjadi guru bagi banyak ulama besar, termasuk tokoh-tokoh yang kelak mendirikan organisasi Islam di Indonesia. Ia sangat produktif, menulis puluhan kitab dalam berbagai bidang — tafsir, fikih, tauhid, dan akhlak — yang sampai hari ini menjadi rujukan di pesantren-pesantren, seperti Tafsir Marah Labid, Nashaihul Ibad, dan Sullam al-Munajat.

Melalui murid-murid dan kitab-kitabnya, pengaruh Syekh Nawawi mengalir kembali ke Nusantara dan membentuk tradisi keilmuan pesantren yang kokoh.

Hikmah: seorang guru sejati hidup melalui murid dan karyanya. Ilmu yang diajarkan dengan ikhlas akan terus berbuah lama setelah sang guru tiada.

Sumber & Catatan: kiprah Syekh Nawawi terdokumentasi sangat kuat — puluhan kitabnya masih dicetak dan diajarkan di pesantren hingga kini, dan silsilah keilmuan (sanad) murid-muridnya tercatat. Gelar "Sayyid Ulama al-Hijaz" dan kedudukannya sebagai pengajar di Makkah adalah bagian dari sejarah keilmuan Islam yang diakui luas.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Sheikh Nawawi al-Bantani — the Master of the Scholars of the Hijaz', 'ulama-nusantara-06-nawawi-al-bantani', 'en', 'ulama-nusantara', 7, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Sheikh Nawawi al-Bantani (1813–1897) came from Banten and became one of the most celebrated archipelago scholars in the Muslim world. From his youth he sought knowledge as far as Makkah, then settled and taught there for decades, until he died and was buried in Ma''la, Makkah.

The depth of his knowledge earned him the title "Sayyid Ulama al-Hijaz" (chief of the scholars of the Hijaz). He taught in the Sacred Mosque and became a teacher to many great scholars, including figures who would later found Islamic organisations in Indonesia. He was highly prolific, writing dozens of books across many fields — Qur''anic commentary, jurisprudence, theology, and character — that remain references in pesantren to this day, such as Tafsir Marah Labid, Nashaih al-''Ibad, and Sullam al-Munajat.

Through his students and his books, Sheikh Nawawi''s influence flowed back to the archipelago and shaped a firm tradition of pesantren scholarship.

Reflection: a true teacher lives on through his students and his works. Knowledge taught with sincerity keeps bearing fruit long after the teacher is gone.

Sources & Notes: Sheikh Nawawi''s career is very strongly documented — dozens of his books are still printed and taught in pesantren today, and the scholarly chains (sanad) of his students are recorded. The title "Sayyid Ulama al-Hijaz" and his position as a teacher in Makkah are part of a widely recognised history of Islamic scholarship.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Syekh Ahmad Khatib al-Minangkabawi — Imam dari Tanah Minang', 'ulama-nusantara-07-ahmad-khatib-al-minangkabawi', 'id', 'ulama-nusantara', 8, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Ahmad Khatib al-Minangkabawi (1860–1916) adalah ulama besar asal Minangkabau, Sumatra Barat, yang mencapai kedudukan istimewa di tanah suci: ia menjadi imam dan pengajar di Masjidil Haram, Makkah, sebuah kehormatan langka bagi seorang ulama dari Nusantara.

Sebagai pengajar di pusat dunia Islam, ia menjadi guru bagi banyak murid dari Nusantara yang belajar di Makkah. Yang menarik, dari didikannya lahir tokoh-tokoh dengan corak pemikiran berbeda yang kelak membentuk dua arus besar Islam Indonesia — termasuk para pendiri Nahdlatul Ulama dan Muhammadiyah. Ini menunjukkan keluasan dan keikhlasannya sebagai guru: ia mendidik, lalu membiarkan murid-muridnya berkembang sesuai ijtihad masing-masing.

Ahmad Khatib juga menulis berbagai karya dan dikenal kritis terhadap praktik-praktik yang ia nilai menyimpang, mendorong pemurnian pemahaman agama.

Hikmah: guru yang besar adalah yang melahirkan murid-murid yang mampu berpikir mandiri. Perbedaan pandangan di antara murid bukanlah kegagalan, melainkan bukti luasnya ilmu yang ditanamkan.

Sumber & Catatan: kedudukan Ahmad Khatib sebagai imam Masjidil Haram dan gurunya para pendiri NU (KH Hasyim Asy''ari) dan Muhammadiyah (KH Ahmad Dahlan) adalah fakta sejarah yang tercatat dalam biografi kedua tokoh tersebut dan sejarah keilmuan Islam Indonesia. Karya-karyanya sebagian masih dapat ditemukan.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Sheikh Ahmad Khatib al-Minangkabawi — an Imam from the Minang Land', 'ulama-nusantara-07-ahmad-khatib-al-minangkabawi', 'en', 'ulama-nusantara', 8, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Ahmad Khatib al-Minangkabawi (1860–1916) was a great scholar from Minangkabau, West Sumatra, who reached a special station in the holy land: he became an imam and teacher in the Sacred Mosque of Makkah, a rare honour for a scholar from the archipelago.

As a teacher at the centre of the Muslim world, he became a teacher to many students from the archipelago studying in Makkah. Remarkably, from his tutelage came figures of differing strands of thought who would later shape the two great currents of Indonesian Islam — including the founders of Nahdlatul Ulama and Muhammadiyah. This shows the breadth and sincerity of his teaching: he taught, then let his students develop according to their own reasoning.

Ahmad Khatib also wrote various works and was known for a critical stance toward practices he judged deviant, urging a purification of religious understanding.

Reflection: a great teacher is one who produces students able to think independently. Difference of view among students is not a failure but proof of the breadth of the knowledge instilled.

Sources & Notes: Ahmad Khatib''s position as an imam of the Sacred Mosque and as teacher of the founders of NU (KH Hasyim Asy''ari) and Muhammadiyah (KH Ahmad Dahlan) is a historical fact recorded in the biographies of both figures and in the history of Indonesian Islamic scholarship. Some of his works can still be found.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'KH Hasyim Asy''ari — Pendiri Nahdlatul Ulama', 'ulama-nusantara-08-hasyim-asyari', 'id', 'ulama-nusantara', 9, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Kiai Haji Hasyim Asy''ari (1871–1947) adalah salah satu ulama paling berpengaruh dalam sejarah Indonesia modern. Lahir di Jombang, Jawa Timur, ia menuntut ilmu di berbagai pesantren dan kemudian di Makkah, berguru antara lain kepada Syekh Ahmad Khatib al-Minangkabawi dan ulama besar lainnya.

Sekembalinya ke tanah air, ia mendirikan Pesantren Tebuireng di Jombang, yang menjadi salah satu pesantren paling berpengaruh di Indonesia. Pada tahun 1926, ia menjadi tokoh utama pendirian Nahdlatul Ulama (NU), organisasi Islam yang kini menjadi salah satu organisasi keagamaan terbesar di dunia, yang menaungi tradisi pesantren dan ahlussunnah wal jamaah.

Peran KH Hasyim Asy''ari tidak berhenti di bidang keagamaan. Pada masa perjuangan kemerdekaan, ia mengeluarkan seruan yang membangkitkan semangat melawan penjajah — yang dikenal dalam sejarah sebagai Resolusi Jihad tahun 1945. Ia diakui sebagai Pahlawan Nasional Indonesia.

Hikmah: ilmu, lembaga, dan cinta tanah air dapat berpadu dalam diri seorang ulama. Warisan terbesar bukan hanya kitab, tetapi juga lembaga dan umat yang terus hidup meneruskan kebaikan.

Sumber & Catatan: kiprah KH Hasyim Asy''ari termasuk yang paling terdokumentasi — pendirian Pesantren Tebuireng, pendirian Nahdlatul Ulama (1926), Resolusi Jihad (1945), dan gelar Pahlawan Nasional adalah fakta sejarah resmi. Ia juga menulis sejumlah kitab yang masih diajarkan, seperti Adabul ''Alim wal Muta''allim.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'KH Hasyim Asy''ari — Founder of Nahdlatul Ulama', 'ulama-nusantara-08-hasyim-asyari', 'en', 'ulama-nusantara', 9, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Kiai Haji Hasyim Asy''ari (1871–1947) was one of the most influential scholars in the history of modern Indonesia. Born in Jombang, East Java, he sought knowledge in various pesantren and then in Makkah, studying under, among others, Sheikh Ahmad Khatib al-Minangkabawi and other great scholars.

On returning home, he founded the Tebuireng pesantren in Jombang, which became one of the most influential pesantren in Indonesia. In 1926 he was the leading figure in founding Nahdlatul Ulama (NU), an Islamic organisation that is today one of the largest religious organisations in the world, upholding the pesantren tradition and Ahl al-Sunnah wa al-Jama''ah.

KH Hasyim Asy''ari''s role did not stop at religion. During the struggle for independence, he issued a call that stirred the spirit of resistance against the colonisers — known in history as the Resolusi Jihad (Jihad Resolution) of 1945. He is recognised as an Indonesian National Hero.

Reflection: knowledge, institutions, and love of country can be joined in one scholar. The greatest legacy is not only books but also institutions and a community that keep on carrying the good forward.

Sources & Notes: KH Hasyim Asy''ari''s career is among the most documented — the founding of the Tebuireng pesantren, the founding of Nahdlatul Ulama (1926), the Jihad Resolution (1945), and the National Hero title are official historical facts. He also wrote a number of books still taught, such as Adab al-''Alim wa al-Muta''allim.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'KH Ahmad Dahlan — Pendiri Muhammadiyah', 'ulama-nusantara-09-ahmad-dahlan', 'id', 'ulama-nusantara', 10, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Kiai Haji Ahmad Dahlan (1868–1923) lahir di Yogyakarta dengan nama Muhammad Darwis. Seperti banyak ulama sezamannya, ia menuntut ilmu hingga ke Makkah dan berguru kepada ulama besar, termasuk Syekh Ahmad Khatib al-Minangkabawi.

Pada tahun 1912, ia mendirikan Muhammadiyah, sebuah organisasi Islam yang menekankan pemurnian ajaran, pendidikan modern, dan amal sosial. Muhammadiyah menjadi pelopor dalam mendirikan sekolah-sekolah yang memadukan ilmu agama dan ilmu umum, rumah sakit, panti asuhan, dan berbagai lembaga sosial. Semangatnya berangkat dari penghayatan mendalam terhadap Surah Al-Ma''un — bahwa iman harus berbuah kepedulian nyata kepada anak yatim dan kaum miskin.

Kontribusi KH Ahmad Dahlan mengubah wajah pendidikan dan kesejahteraan umat Islam Indonesia. Ia diakui sebagai Pahlawan Nasional Indonesia.

Hikmah: iman yang benar mendorong amal nyata. KH Ahmad Dahlan mengajarkan bahwa memahami satu surah Al-Qur''an dengan sungguh-sungguh bisa melahirkan gerakan sosial yang mengubah bangsa.

Sumber & Catatan: kiprah KH Ahmad Dahlan terdokumentasi resmi — pendirian Muhammadiyah (1912), jaringan sekolah, rumah sakit, dan panti asuhannya yang masih beroperasi hingga kini, serta gelar Pahlawan Nasional. Kisah kegigihannya mengajarkan Surah Al-Ma''un secara berulang termuat dalam berbagai catatan sejarah Muhammadiyah.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'KH Ahmad Dahlan — Founder of Muhammadiyah', 'ulama-nusantara-09-ahmad-dahlan', 'en', 'ulama-nusantara', 10, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Kiai Haji Ahmad Dahlan (1868–1923) was born in Yogyakarta with the name Muhammad Darwis. Like many scholars of his time, he sought knowledge as far as Makkah and studied under great scholars, including Sheikh Ahmad Khatib al-Minangkabawi.

In 1912 he founded Muhammadiyah, an Islamic organisation stressing the purification of teaching, modern education, and social welfare. Muhammadiyah became a pioneer in founding schools that combined religious and general knowledge, hospitals, orphanages, and various social institutions. Its spirit sprang from a deep reflection on Surah Al-Ma''un — that faith must bear the fruit of real care for orphans and the poor.

KH Ahmad Dahlan''s contribution changed the face of education and welfare for Indonesian Muslims. He is recognised as an Indonesian National Hero.

Reflection: true faith drives real action. KH Ahmad Dahlan teaches that understanding a single surah of the Qur''an in earnest can give rise to a social movement that changes a nation.

Sources & Notes: KH Ahmad Dahlan''s career is officially documented — the founding of Muhammadiyah (1912), its network of schools, hospitals, and orphanages still operating today, and the National Hero title. The account of his persistence in repeatedly teaching Surah Al-Ma''un is recorded in various histories of Muhammadiyah.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Buya Hamka — Ulama, Sastrawan, dan Penulis Tafsir Al-Azhar', 'ulama-nusantara-10-buya-hamka', 'id', 'ulama-nusantara', 11, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Haji Abdul Malik Karim Amrullah (1908–1981), yang dikenal luas sebagai Buya Hamka, adalah ulama, sastrawan, dan pemikir besar Indonesia abad ke-20. Lahir di Maninjau, Sumatra Barat, ia menempa diri lewat belajar mandiri, merantau, dan pergaulan luas, hingga menjadi salah satu tokoh paling dihormati di negerinya.

Hamka istimewa karena memadukan dua dunia: keulamaan dan kesusastraan. Ia menulis novel-novel terkenal seperti "Tenggelamnya Kapal Van der Wijck" dan "Di Bawah Lindungan Ka''bah", sekaligus karya keislaman yang mendalam. Karya monumentalnya adalah "Tafsir Al-Azhar", tafsir lengkap Al-Qur''an dalam bahasa Indonesia — sebagian besar ditulis justru ketika ia dipenjara pada masa Orde Lama, menjadikan penjara sebagai tempat lahirnya karya besar.

Ia menjadi Ketua Majelis Ulama Indonesia (MUI) yang pertama. Sikapnya yang teguh sekaligus santun membuatnya dihormati lawan maupun kawan. Ia diakui sebagai Pahlawan Nasional Indonesia.

Hikmah: keteguhan iman dapat mengubah kesulitan menjadi karya. Dari balik jeruji penjara, Hamka justru melahirkan tafsir yang memberi manfaat bagi jutaan orang — bukti bahwa niat baik dan ilmu tak bisa dipenjara.

Sumber & Catatan: kiprah Buya Hamka terdokumentasi sangat kuat dan berada dalam sejarah modern — karya-karyanya (Tafsir Al-Azhar, novel-novelnya) masih dicetak luas, jabatannya sebagai Ketua MUI pertama (1975), pemenjaraannya, dan gelar Pahlawan Nasional (2011) adalah fakta yang tercatat resmi.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Buya Hamka — Scholar, Man of Letters, and Author of Tafsir Al-Azhar', 'ulama-nusantara-10-buya-hamka', 'en', 'ulama-nusantara', 11, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Haji Abdul Malik Karim Amrullah (1908–1981), widely known as Buya Hamka, was a great Indonesian scholar, writer, and thinker of the 20th century. Born in Maninjau, West Sumatra, he shaped himself through self-study, travel, and wide association, until he became one of the most respected figures in his country.

Hamka was remarkable for uniting two worlds: scholarship and literature. He wrote famous novels such as "The Sinking of the Van der Wijck" and "Beneath the Protection of the Ka''bah," alongside profound Islamic works. His monumental work is "Tafsir Al-Azhar," a complete commentary on the Qur''an in Indonesian — much of it written precisely while he was imprisoned under the Old Order, making the prison the birthplace of a great work.

He became the first chairman of the Indonesian Ulama Council (MUI). His firm yet gentle stance won him the respect of opponents and friends alike. He is recognised as an Indonesian National Hero.

Reflection: firmness of faith can turn hardship into a work of lasting good. From behind prison bars, Hamka brought forth a commentary that benefits millions — proof that good intention and knowledge cannot be imprisoned.

Sources & Notes: Buya Hamka''s career is very strongly documented and sits within modern history — his works (Tafsir Al-Azhar, his novels) are still widely printed, his post as the first chairman of MUI (1975), his imprisonment, and the National Hero title (2011) are officially recorded facts.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Warisan Ulama Nusantara — Ilmu yang Terus Mengalir', 'ulama-nusantara-11-warisan', 'id', 'ulama-nusantara', 12, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Menelusuri kisah para ulama Nusantara, dari Hamzah Fansuri di Aceh hingga Buya Hamka di zaman modern, kita menemukan satu benang merah: mereka semua menjadikan ilmu sebagai jalan pengabdian, dan warisan mereka terus hidup jauh melampaui usia mereka.

Warisan itu berbentuk nyata. Ada kitab-kitab yang masih dibaca dan diajarkan di pesantren hingga hari ini. Ada lembaga-lembaga besar — Nahdlatul Ulama, Muhammadiyah, ribuan pesantren, sekolah, rumah sakit, dan universitas — yang lahir dari gagasan mereka. Ada tradisi keilmuan dan sanad yang tak terputus, menghubungkan santri masa kini dengan ulama masa silam, terus sampai ke Rasulullah.

Yang tak kalah penting, mereka mewariskan teladan sikap: memadukan kedalaman ilmu dengan kepedulian sosial, keteguhan prinsip dengan kelembutan akhlak, dan cinta agama dengan cinta tanah air. Islam Nusantara yang ramah dan berilmu adalah buah dari jerih payah mereka.

Hikmah: ilmu yang diamalkan dan diajarkan adalah sedekah jariyah yang tak pernah putus. Para ulama Nusantara mengajarkan bahwa hidup yang paling bermakna adalah hidup yang manfaatnya terus mengalir untuk umat, generasi demi generasi.

Sumber & Catatan: kesimpulan ini disarikan dari jejak nyata yang dapat diverifikasi — karya, lembaga, dan tradisi keilmuan yang masih hidup hingga kini. Setiap tokoh dalam seri ini disertai catatan sumbernya masing-masing pada babnya. Untuk pendalaman, pembaca dianjurkan merujuk pada biografi resmi dan kajian sejarah Islam Nusantara yang kredibel.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');
INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'The Legacy of the Archipelago''s Scholars — Knowledge That Keeps Flowing', 'ulama-nusantara-11-warisan', 'en', 'ulama-nusantara', 12, (SELECT id FROM categories WHERE slug = 'kisah-ulama-nusantara'), 'Tracing the stories of the archipelago''s scholars, from Hamzah Fansuri in Aceh to Buya Hamka in the modern age, we find one common thread: they all made knowledge a path of service, and their legacy lives on far beyond their lifetimes.

That legacy is tangible. There are books still read and taught in pesantren to this day. There are great institutions — Nahdlatul Ulama, Muhammadiyah, thousands of pesantren, schools, hospitals, and universities — born from their ideas. There is an unbroken tradition of learning and sanad, connecting today''s students with the scholars of old, on and on back to the Messenger of God.

No less important, they left an example of character: uniting depth of knowledge with social concern, firmness of principle with gentleness of conduct, and love of religion with love of country. The friendly, learned Islam of the archipelago is the fruit of their toil.

Reflection: knowledge acted upon and taught is an endless flowing charity. The scholars of the archipelago teach that the most meaningful life is one whose benefit keeps flowing to the community, generation after generation.

Sources & Notes: this conclusion is distilled from tangible, verifiable traces — the works, institutions, and scholarly traditions still alive today. Each figure in this series carries its own source note in its chapter. For deeper study, readers are encouraged to consult official biographies and credible histories of Islam in the archipelago.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  NULL, NULL, datetime('now');

